import { Fragment, useContext } from 'react';

import { AnnotationsMarkersDisplay } from './AnnotationsMarkersDisplay.js';
import { getTokenComputedStyle } from '../../../../../utils/getTokenComputedStyle.js';
import {
  EMPHASIZED_TRACK_SEPARATOR_COLOR,
  LABEL_OFFSET,
  MARKER_LABEL_PADDING,
  TRACK_SEPARATOR_COLOR,
} from '../../../constants.js';
import { AnnotationsConfigContext } from '../../../contexts/AnnotationsConfig.context.js';
import { MarkerAtomProps } from '../../../types/marker.js';
import { TrackAtomProps } from '../../../types/track.js';
import { getTrackSeparatorOffset } from '../../../utils/get-track-separator-offset.js';
import { TrackDisplayContext } from '../context/track-display.context.js';
import { AnnotationsLabelRenderer } from '../renderers/AnnotationsLabelRenderer.js';
import { AnnotationsLineRenderer } from '../renderers/AnnotationsLineRenderer.js';

interface AnnotationsTrackDisplayProps extends TrackAtomProps {
  trackIndex: number;
  drawTopLine?: boolean;
  markers: MarkerAtomProps[];
  emphasizeBottomLine?: boolean;
}

const getLabelYPosition = (index: number) =>
  getTrackSeparatorOffset(index) + LABEL_OFFSET;

export const AnnotationsTrackDisplay = (
  props: AnnotationsTrackDisplayProps,
) => {
  const { drawTopLine, label, markers, trackIndex, emphasizeBottomLine } =
    props;
  const { labelsWidth, trackWidth, showLabels } = useContext(
    AnnotationsConfigContext,
  );

  const trackFinalXPosition = labelsWidth + trackWidth;
  const topLineY = getTrackSeparatorOffset(trackIndex);
  const bottomLineY = getTrackSeparatorOffset(trackIndex + 1);
  const bottomLineColor = emphasizeBottomLine
    ? EMPHASIZED_TRACK_SEPARATOR_COLOR
    : TRACK_SEPARATOR_COLOR;

  return (
    <>
      {drawTopLine && (
        <AnnotationsLineRenderer
          source={{ x: labelsWidth, y: topLineY }}
          destination={{ x: trackFinalXPosition, y: topLineY }}
          strokeColor={getTokenComputedStyle(TRACK_SEPARATOR_COLOR)}
        />
      )}

      <Fragment>
        {showLabels && label && (
          <AnnotationsLabelRenderer
            text={label}
            x={labelsWidth - MARKER_LABEL_PADDING}
            y={getLabelYPosition(trackIndex)}
            maxWidth={labelsWidth - MARKER_LABEL_PADDING}
            ellipsis
          />
        )}
        <TrackDisplayContext.Provider
          value={{
            offsetX: labelsWidth,
            trackIndex,
          }}
        >
          <AnnotationsMarkersDisplay markers={markers} />
        </TrackDisplayContext.Provider>
        <AnnotationsLineRenderer
          source={{ x: labelsWidth, y: bottomLineY }}
          destination={{
            x: trackFinalXPosition,
            y: bottomLineY,
          }}
          strokeColor={getTokenComputedStyle(bottomLineColor)}
        />
      </Fragment>
    </>
  );
};

AnnotationsTrackDisplay['displayName'] = 'AnnotationsTrackDisplay';
